sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {

	//create a task link with the current sys_id
	//KT - STRY0050727
	var task_link = 'discovertaskerportal?sys_id='+ current.sys_id +'&view=sp&id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance';

	//create link for email template
	template.print("<span style='font-family: georgia, palatino; font-size: 12pt;'><a href='"+ task_link +"'>"+ current.task_name+'</a></span>');

})(current, template, email, email_action, event);
